        size_t fileStart = numPos;
        while (numPos < line.size() && line[numPos] != '"') numPos++;
        currentFile = line.substr(fileStart, numPos - fileStart);
      }
    } else {
      sourceLines.push_back(line);
      currentLine++;
    }
  }

  // 现在使用简单的逐字符分析来跟踪位置
  // 重新创建 lexer
  antlr4::ANTLRInputStream input2(processedContent);
  SYsULexer lexer2(&input2);
  antlr4::CommonTokenStream tokens2(&lexer2);
  tokens2.fill();

  // 构建行内容映射
  std::vector<std::string> lineContents;
  currentLine = 1;
  currentFile = argv[1];

  iss.clear();
  iss.str(content);

  int logicalLine = 1;
  while (std::getline(iss, line)) {
    size_t pos = 0;
    while (pos < line.size() && (line[pos] == ' ' || line[pos] == '\t')) pos++;

    if (pos < line.size() && line[pos] == '#') {
      size_t numPos = pos + 1;
      while (numPos < line.size() && (line[numPos] == ' ' || line[numPos] == '\t')) numPos++;

      size_t numStart = numPos;
      while (numPos < line.size() && line[numPos] >= '0' && line[numPos] <= '9') numPos++;

      if (numPos > numStart) {
        logicalLine = std::stoi(line.substr(numStart, numPos - numStart));
      }

      while (numPos < line.size() && (line[numPos] == ' ' || line[numPos] == '\t')) numPos++;

      if (numPos < line.size() && line[numPos] == '"') {
        numPos++;
        size_t fileStart = numPos;
        while (numPos < line.size() && line[numPos] != '"') numPos++;
        currentFile = line.substr(fileStart, numPos - fileStart);
      }
    } else {
      while ((int)lineContents.size() < logicalLine) {
        lineContents.push_back("");
      }
      lineContents[logicalLine - 1] = line;
      logicalLine++;
    }
  }

  // 处理 tokens
  int tokenIndex = 0;
  int currentSrcLine = 1;
  int currentSrcCol = 1;
  std::string srcFile = argv[1];
  bool atLineStart = true;
  bool hasLeadingSpace = false;

  // 逐行扫描源代码来匹配 tokens
  for (auto&& token : tokens2.getTokens()) {
    std::string tokenText = token->getText();

    if (tokenText == "<EOF>") {
      // 输出 eof
      auto& vocabulary = lexer2.getVocabulary();
      auto tokenTypeName = std::string(vocabulary.getSymbolicName(token->getType()));
      outFile << "eof ''\t\tLoc=<" << srcFile << ":" << currentSrcLine << ":" << (currentSrcCol) << ">" << std::endl;
      break;
    }

    auto& vocabulary = lexer2.getVocabulary();
    auto tokenTypeName = std::string(vocabulary.getSymbolicName(token->getType()));
    if (tokenTypeName.empty()) tokenTypeName = "<UNKNOWN>";
    if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
      tokenTypeName = tokenTypeMapping[tokenTypeName];
    }

    // 查找这个 token 在源代码中的位置
    bool found = false;
    while (!found && currentSrcLine <= (int)lineContents.size()) {
      const std::string& srcLine = lineContents[currentSrcLine - 1];

      // 在当前行查找 token
      size_t searchStart = currentSrcCol - 1;
      if (searchStart >= srcLine.size()) {
        currentSrcLine++;
        currentSrcCol = 1;
        atLineStart = true;
        hasLeadingSpace = false;
        continue;
      }

      // 查找 token
      size_t foundPos = srcLine.find(tokenText, searchStart);

      if (foundPos != std::string::npos) {
        // 检查 token 前面的内容
        std::string beforeToken = srcLine.substr(searchStart, foundPos - searchStart);
        bool isEmptyBefore = beforeToken.empty() || 
                            (beforeToken.find_first_not_of(' ') == std::string::npos && 
                             beforeToken.find_first_not_of('\t') == std::string::npos);

        if (searchStart == 0 && isEmptyBefore) {
          atLineStart = true;
        } else {
          atLineStart = false;
        }

        hasLeadingSpace = !isEmptyBefore || (searchStart > 0);

        // 检查是否有前导空白
        if (searchStart < foundPos) {
          hasLeadingSpace = true;
        } else if (searchStart == 0 && foundPos == 0) {
          atLineStart = true;
          hasLeadingSpace = false;
        }

        // 输出 token
        outFile << tokenTypeName << " '" << tokenText << "'";
        if (atLineStart) {
          outFile << "\t [StartOfLine]";
        }
        if (hasLeadingSpace && !atLineStart) {
          outFile << " [LeadingSpace]";
        }
        outFile << "\tLoc=<" << srcFile << ":" << currentSrcLine << ":" << (foundPos + 1) << ">" << std::endl;

        currentSrcCol = foundPos + tokenText.length() + 1;
        atLineStart = false;
        hasLeadingSpace = false;
        found = true;
      } else {
        // 没找到，移到下一行
        currentSrcLine++;
        currentSrcCol = 1;
        atLineStart = true;
        hasLeadingSpace = false;
      }
    }
  }

  return 0;
}

